package com.foodordering.krishnafoods.admin.activityimport android.Manifestimport android.content.pm.PackageManagerimport android.graphics.Bitmapimport android.graphics.Colorimport android.graphics.ImageDecoderimport android.net.ConnectivityManagerimport android.net.NetworkCapabilitiesimport android.net.Uriimport android.os.Buildimport android.os.Bundleimport android.provider.MediaStoreimport android.util.Logimport android.view.Viewimport android.widget.ArrayAdapterimport android.widget.Buttonimport android.widget.ImageViewimport android.widget.Toastimport androidx.activity.OnBackPressedCallbackimport androidx.activity.result.ActivityResultLauncherimport androidx.activity.result.PickVisualMediaRequestimport androidx.activity.result.contract.ActivityResultContractsimport androidx.appcompat.app.AlertDialogimport androidx.appcompat.app.AppCompatActivityimport androidx.core.app.ActivityCompatimport androidx.core.content.ContextCompatimport androidx.core.content.FileProviderimport androidx.core.view.ViewCompatimport androidx.core.view.WindowCompatimport androidx.core.view.WindowInsetsCompatimport androidx.lifecycle.lifecycleScopeimport com.airbnb.lottie.LottieAnimationViewimport com.cloudinary.android.MediaManagerimport com.cloudinary.android.callback.ErrorInfoimport com.cloudinary.android.callback.UploadCallbackimport com.foodordering.krishnafoods.BuildConfigimport com.foodordering.krishnafoods.Rimport com.google.android.material.appbar.MaterialToolbarimport com.google.android.material.textfield.MaterialAutoCompleteTextViewimport com.google.android.material.textfield.TextInputEditTextimport com.google.android.material.textfield.TextInputLayoutimport com.google.firebase.auth.FirebaseAuthimport com.google.firebase.firestore.FirebaseFirestoreimport kotlinx.coroutines.Dispatchersimport kotlinx.coroutines.launchimport kotlinx.coroutines.withContextimport java.io.Fileimport java.io.FileOutputStreamclass AddItemActivity : AppCompatActivity() {    // UI Elements    private lateinit var etFoodName: TextInputEditText    private lateinit var etOriginalPrice: TextInputEditText    private lateinit var etOfferedPrice: TextInputEditText    private lateinit var spinnerCategory: MaterialAutoCompleteTextView    private lateinit var spinnerWeight: MaterialAutoCompleteTextView    private lateinit var btnAddFood: Button    private lateinit var ivFoodImage: ImageView    private lateinit var lottieProgressBar: LottieAnimationView    private lateinit var layoutFoodName: TextInputLayout    private lateinit var layoutFoodPrice: TextInputLayout    private lateinit var layoutOfferedPrice: TextInputLayout    // Image handling - UPDATED    private var selectedImageUri: Uri? = null    private var imageUrl: String? = null    private lateinit var photoPickerLauncher: ActivityResultLauncher<PickVisualMediaRequest>    private lateinit var cameraLauncher: ActivityResultLauncher<Uri>    private var cameraImageUri: Uri? = null    private var isUploading = false    // Firebase    private val db = FirebaseFirestore.getInstance()    private val auth = FirebaseAuth.getInstance()    // Options    private val categories = mutableListOf<String>()    private val liquidCategories = mutableListOf<String>()    private val solidWeightOptions = mutableListOf<String>()    private val liquidVolumeOptions = mutableListOf<String>()    companion object {        private var cloudinaryInitialized = false        private const val CAMERA_PERMISSION_CODE = 101    }    override fun onCreate(savedInstanceState: Bundle?) {        super.onCreate(savedInstanceState)        setContentView(R.layout.admin_activity_add_item)        val toolbar = findViewById<MaterialToolbar>(R.id.AddFood)        toolbar.setNavigationOnClickListener { handleBackPress() }        supportActionBar?.hide()        WindowCompat.setDecorFitsSystemWindows(window, false)        window.statusBarColor = Color.TRANSPARENT        WindowCompat.setDecorFitsSystemWindows(window, false)        ViewCompat.setOnApplyWindowInsetsListener(toolbar) { v, insets ->            val systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars())            v.setPadding(v.paddingLeft, systemBars.top, v.paddingRight, v.paddingBottom)            insets        }        initializeViews()        initializeLaunchers()        fetchCategoriesFromFirebase()        fetchOptionsFromFirebase()        setupClickListeners()        initCloudinary()        setupBackPressHandler()    }    private fun initializeViews() {        etFoodName = findViewById(R.id.etFoodName)        etOriginalPrice = findViewById(R.id.etFoodPrice)        etOfferedPrice = findViewById(R.id.etOfferedPrice)        spinnerCategory = findViewById(R.id.spinnerCategory)        spinnerWeight = findViewById(R.id.spinnerWeight)        btnAddFood = findViewById(R.id.btnAddFood)        ivFoodImage = findViewById(R.id.ivFoodImages)        lottieProgressBar = findViewById(R.id.lottieProgressBar)        layoutFoodName = findViewById(R.id.layoutFoodName)        layoutFoodPrice = findViewById(R.id.layoutFoodPrice)        layoutOfferedPrice = findViewById(R.id.layoutOfferedPrice)        lottieProgressBar.setAnimation(R.raw.loading_animation)    }    // UPDATED: Use Photo Picker instead of GetContent    private fun initializeLaunchers() {        // Photo Picker - No permissions required!        photoPickerLauncher = registerForActivityResult(            ActivityResultContracts.PickVisualMedia()        ) { uri ->            uri?.let {                selectedImageUri = it                ivFoodImage.setImageURI(it)            }        }        cameraLauncher = registerForActivityResult(            ActivityResultContracts.TakePicture()        ) { success ->            if (success) {                cameraImageUri?.let {                    selectedImageUri = it                    ivFoodImage.setImageURI(it)                }            }        }    }    private fun showLoading() {        isUploading = true        lottieProgressBar.visibility = View.VISIBLE        lottieProgressBar.playAnimation()        btnAddFood.isEnabled = false    }    private fun hideLoading() {        isUploading = false        lottieProgressBar.cancelAnimation()        lottieProgressBar.visibility = View.GONE        btnAddFood.isEnabled = true    }    private fun setupBackPressHandler() {        val callback = object : OnBackPressedCallback(true) {            override fun handleOnBackPressed() {                handleBackPress()            }        }        onBackPressedDispatcher.addCallback(this, callback)    }    private fun handleBackPress() {        if (isUploading) {            AlertDialog.Builder(this)                .setTitle(R.string.warning)                .setMessage(R.string.back_press_warning)                .setPositiveButton(R.string.yes) { _, _ -> finish() }                .setNegativeButton(R.string.no) { dialog, _ -> dialog.dismiss() }                .setCancelable(false)                .show()        } else {            finish()        }    }    private fun fetchCategoriesFromFirebase() {        db.collection("categories").get()            .addOnSuccessListener { docs ->                categories.clear()                docs.forEach { it.getString("name")?.let(categories::add) }                if (categories.isEmpty()) categories.addAll(listOf("Namkeen", "Farsan", "Drinks", "Sweets", "Juices"))                setupCategorySpinner()            }            .addOnFailureListener {                categories.addAll(listOf("Namkeen", "Farsan", "Drinks", "Sweets", "Juices"))                setupCategorySpinner()            }    }    private fun fetchOptionsFromFirebase() {        val defaultLiquid = listOf("Drinks", "Juices", "Milk", "Liquid")        val defaultSolid = listOf("250g", "500g", "1kg", "2kg")        val defaultVolume = listOf("250ml", "500ml", "1L", "2L")        db.collection("options").document("liquidCategories").get()            .addOnSuccessListener {                liquidCategories.clear()                val fetchedValues = (it.get("values") as? List<*>)?.filterIsInstance<String>()                if (!fetchedValues.isNullOrEmpty()) {                    liquidCategories.addAll(fetchedValues)                } else {                    liquidCategories.addAll(defaultLiquid)                }            }            .addOnFailureListener { liquidCategories.addAll(defaultLiquid) }        db.collection("options").document("solidWeightOptions").get()            .addOnSuccessListener {                solidWeightOptions.clear()                val fetchedValues = (it.get("values") as? List<*>)?.filterIsInstance<String>()                if (!fetchedValues.isNullOrEmpty()) {                    solidWeightOptions.addAll(fetchedValues)                } else {                    solidWeightOptions.addAll(defaultSolid)                }            }            .addOnFailureListener { solidWeightOptions.addAll(defaultSolid) }        db.collection("options").document("liquidVolumeOptions").get()            .addOnSuccessListener {                liquidVolumeOptions.clear()                val fetchedValues = (it.get("values") as? List<*>)?.filterIsInstance<String>()                if (!fetchedValues.isNullOrEmpty()) {                    liquidVolumeOptions.addAll(fetchedValues)                } else {                    liquidVolumeOptions.addAll(defaultVolume)                }            }            .addOnFailureListener { liquidVolumeOptions.addAll(defaultVolume) }    }    private fun setupCategorySpinner() {        val adapter = ArrayAdapter(this, android.R.layout.simple_dropdown_item_1line, categories)        spinnerCategory.setAdapter(adapter)        spinnerCategory.setOnItemClickListener { _, _, position, _ ->            val isLiquid = liquidCategories.contains(categories[position])            setupWeightSpinner(isLiquid)        }    }    private fun setupWeightSpinner(isLiquid: Boolean) {        val adapter = ArrayAdapter(            this,            android.R.layout.simple_dropdown_item_1line,            if (isLiquid) liquidVolumeOptions else solidWeightOptions        )        spinnerWeight.setAdapter(adapter)    }    private fun setupClickListeners() {        ivFoodImage.setOnClickListener { selectImageSource() }        btnAddFood.setOnClickListener { validateAndUploadFood() }    }    // UPDATED    private fun selectImageSource() {        val options = arrayOf("Camera", "Gallery")        AlertDialog.Builder(this)            .setTitle(R.string.select_image_source)            .setItems(options) { _, choice ->                when (choice) {                    0 -> openCamera()                    1 -> openPhotoPicker() // CHANGED                }            }.show()    }    // NEW METHOD    private fun openPhotoPicker() {        photoPickerLauncher.launch(            PickVisualMediaRequest(ActivityResultContracts.PickVisualMedia.ImageOnly)        )    }    private fun validateAndUploadFood() {        layoutFoodName.error = null        layoutFoodPrice.error = null        layoutOfferedPrice.error = null        val name = etFoodName.text.toString().trim()        val originalPrice = etOriginalPrice.text.toString().trim().toIntOrNull()        val offeredPrice = etOfferedPrice.text.toString().trim().toIntOrNull()        if (selectedImageUri == null) {            toast(R.string.select_image_error)            return        }        if (name.isEmpty()) {            layoutFoodName.error = getString(R.string.food_name_error)            return        }        if (originalPrice == null || originalPrice <= 0) {            layoutFoodPrice.error = getString(R.string.invalid_price_error)            return        }        if (offeredPrice == null || offeredPrice <= 0) {            layoutOfferedPrice.error = getString(R.string.invalid_price_error)            return        }        if (!isNetworkAvailable()) {            toast(R.string.no_internet)            return        }        if (auth.currentUser == null) {            toast(R.string.login_first)            return        }        showLoading()        btnAddFood.text = getString(R.string.uploading_image)        lifecycleScope.launch { compressAndUpload(selectedImageUri!!) }    }    private suspend fun compressAndUpload(uri: Uri) {        val compressedPath = withContext(Dispatchers.IO) { compressImage(uri) }        if (compressedPath != null) {            // Pass the String path directly            uploadImageToCloudinary(compressedPath)            // File(compressedPath).delete() // <-- REMOVE THIS LINE        } else {            hideLoading()            toast(R.string.image_compress_error)        }    }    private fun initCloudinary() {        if (!cloudinaryInitialized) {            val config = hashMapOf(                "cloud_name" to BuildConfig.CLOUDINARY_CLOUD_NAME,                "api_key" to BuildConfig.CLOUDINARY_API_KEY            )            try {                MediaManager.init(this, config)                cloudinaryInitialized = true            } catch (_: IllegalStateException) {                Log.d("Cloudinary", "Already initialized")            }        }    }    // UPDATED: With proper permission flow    private fun openCamera() {        when {            ContextCompat.checkSelfPermission(                this,                Manifest.permission.CAMERA            ) == PackageManager.PERMISSION_GRANTED -> {                launchCamera()            }            ActivityCompat.shouldShowRequestPermissionRationale(                this,                Manifest.permission.CAMERA            ) -> {                showCameraPermissionRationale()            }            else -> {                showCameraDisclosureDialog()            }        }    }    // NEW: Required disclosure dialog    private fun showCameraDisclosureDialog() {        AlertDialog.Builder(this)            .setTitle("Camera Permission Required")            .setMessage(                "Camera access is needed to take photos of food items.\n\n" +                        "• Photos are uploaded to your menu catalog\n" +                        "• Images are stored securely on our servers\n" +                        "• Not shared with third parties"            )            .setPositiveButton("Continue") { _, _ ->                requestCameraPermission()            }            .setNegativeButton("Cancel") { dialog, _ ->                dialog.dismiss()            }            .setCancelable(false)            .show()    }    // NEW    private fun showCameraPermissionRationale() {        AlertDialog.Builder(this)            .setTitle("Camera Permission Needed")            .setMessage("Camera permission is required to take photos of food items.")            .setPositiveButton("Grant") { _, _ ->                requestCameraPermission()            }            .setNegativeButton("Cancel") { dialog, _ -> dialog.dismiss() }            .show()    }    // NEW    private fun requestCameraPermission() {        ActivityCompat.requestPermissions(            this,            arrayOf(Manifest.permission.CAMERA),            CAMERA_PERMISSION_CODE        )    }    // NEW    private fun launchCamera() {        cameraImageUri = createImageUri()        cameraImageUri?.let { cameraLauncher.launch(it) }    }    override fun onRequestPermissionsResult(        requestCode: Int,        permissions: Array<out String>,        grantResults: IntArray    ) {        super.onRequestPermissionsResult(requestCode, permissions, grantResults)        if (requestCode == CAMERA_PERMISSION_CODE) {            if (grantResults.isNotEmpty() && grantResults[0] == PackageManager.PERMISSION_GRANTED) {                launchCamera()            } else {                Toast.makeText(this, "Camera permission denied", Toast.LENGTH_SHORT).show()            }        }    }    private fun createImageUri(): Uri? = try {        val file = File(filesDir, "camera_${System.currentTimeMillis()}.jpg")        FileProvider.getUriForFile(            this,            "${packageName}.fileprovider",            file        )    } catch (e: Exception) {        Log.e("FileProvider", "Error creating file URI", e)        toast(R.string.camera_setup_error)        null    }    private fun uploadImageToCloudinary(filePath: String) {        MediaManager.get().upload(filePath)             .option("public_id", "food_${System.currentTimeMillis()}")            .unsigned(BuildConfig.CLOUDINARY_UPLOAD_PRESET)            .callback(object : UploadCallback {                override fun onStart(requestId: String) {}                override fun onProgress(requestId: String, bytes: Long, total: Long) {}                override fun onSuccess(requestId: String, resultData: Map<*, *>) {                    imageUrl = resultData["secure_url"]?.toString()                    if (!imageUrl.isNullOrBlank()) addFoodItemToFirestore() else restoreButton()                    // <-- DELETE ON SUCCESS                    File(filePath).delete()                }                override fun onError(requestCode: String, error: ErrorInfo) {                    Log.e("Cloudinary", "Upload Error: ${error.description}")                    restoreButton()                    toast(R.string.image_upload_fail)                    // <-- ALSO DELETE ON ERROR                    File(filePath).delete()                }                override fun onReschedule(requestId: String, error: ErrorInfo) {}            }).dispatch()    }    private fun compressImage(uri: Uri): String? = try {        val bitmap = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {            val source = ImageDecoder.createSource(contentResolver, uri)            ImageDecoder.decodeBitmap(source)        } else {            @Suppress("DEPRECATION")            MediaStore.Images.Media.getBitmap(contentResolver, uri)        }        val file = File(cacheDir, "compressed_${System.currentTimeMillis()}.jpg")        FileOutputStream(file).use { bitmap.compress(Bitmap.CompressFormat.JPEG, 80, it) }        file.absolutePath    } catch (e: Exception) {        Log.e("CompressImage", "Error compressing image", e)        null    }    private fun addFoodItemToFirestore() {        val name = etFoodName.text.toString().trim()        val originalPrice = etOriginalPrice.text.toString().trim().toIntOrNull() ?: 0        val offeredPrice = etOfferedPrice.text.toString().trim().toIntOrNull() ?: 0        val category = spinnerCategory.text.toString()        val weight = spinnerWeight.text.toString()        if (name.isEmpty() || category.isEmpty() || weight.isEmpty() || imageUrl.isNullOrBlank()) {            toast(R.string.fill_all_fields)            restoreButton()            return        }        val foodItem = hashMapOf(            "name" to name,            "originalPrice" to originalPrice,            "offerPrice" to offeredPrice,            "category" to category,            "weight" to weight,            "imageUrl" to imageUrl,            "createdAt" to System.currentTimeMillis(),            "createdBy" to auth.currentUser?.uid        )        db.collection("foods").add(foodItem)            .addOnSuccessListener { toast(R.string.add_food_success); finish() }            .addOnFailureListener {                Log.e("Firestore", "Error adding food item", it)                restoreButton()                toast(R.string.add_food_fail)            }    }    private fun restoreButton() {        btnAddFood.isEnabled = true        btnAddFood.text = getString(R.string.add_item)        hideLoading()    }    private fun isNetworkAvailable(): Boolean {        val connectivityManager = getSystemService(CONNECTIVITY_SERVICE) as ConnectivityManager        val network = connectivityManager.activeNetwork ?: return false        val activeNetwork = connectivityManager.getNetworkCapabilities(network) ?: return false        return when {            activeNetwork.hasTransport(NetworkCapabilities.TRANSPORT_WIFI) -> true            activeNetwork.hasTransport(NetworkCapabilities.TRANSPORT_CELLULAR) -> true            activeNetwork.hasTransport(NetworkCapabilities.TRANSPORT_ETHERNET) -> true            else -> false        }    }    private fun toast(messageRes: Int) {        Toast.makeText(this, messageRes, Toast.LENGTH_SHORT).show()    }}